// patch.go
package features

import (
	"context"
	"net/http"

	api "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/api/v3/apierrors"
	"github.com/openmeterio/openmeter/api/v3/request"
	"github.com/openmeterio/openmeter/openmeter/productcatalog/feature"
	"github.com/openmeterio/openmeter/pkg/framework/commonhttp"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
)

type (
	PatchFeatureRequest  = feature.PatchFeatureInputs
	PatchFeatureResponse = api.Feature
	PatchFeatureParams   = string
	PatchFeatureHandler  httptransport.HandlerWithArgs[PatchFeatureRequest, PatchFeatureResponse, PatchFeatureParams]
)

func (h *handler) PatchFeature() PatchFeatureHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, featureID PatchFeatureParams) (PatchFeatureRequest, error) {
			var body api.PatchFeatureRequest
			if err := request.ParseBody(r, &body); err != nil {
				return PatchFeatureRequest{}, err
			}
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return PatchFeatureRequest{}, err
			}
			return convertPatchRequestToDomain(ns, featureID, body)
		},
		func(ctx context.Context, req PatchFeatureRequest) (PatchFeatureResponse, error) {
			updated, err := h.connector.PatchFeature(ctx, req)
			if err != nil {
				return PatchFeatureResponse{}, err
			}
			return convertFeatureToAPI(updated)
		},
		commonhttp.JSONResponseEncoderWithStatus[PatchFeatureResponse](http.StatusOK),
		httptransport.AppendOptions(
			h.options,
			httptransport.WithOperationName("patch-feature"),
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
			httptransport.WithErrorEncoder(errorEncoder()),
		)...,
	)
}

